// Mapea propiedades Notion → schema Supabase.jobs
// Filtra: necesita upwork_id para idempotencia (UPSERT key).

const out = [];

for (const item of $input.all()) {
  const page = item.json;
  const props = page.properties || {};

  // ── Title ──
  const titleField = props['Job Tittle'] || props['Job Title'] || props['Name'] || props['title'];
  const title =
    titleField?.title?.[0]?.plain_text ||
    titleField?.rich_text?.[0]?.plain_text ||
    null;

  if (!title) continue; // sin título, no procesa

  // ── Description ──
  const descField = props['description'] || props['Description'];
  const description =
    descField?.rich_text?.map(t => t.plain_text).join('').trim() || null;

  // ── Link ──
  const linkField = props['Link'] || props['URL'] || props['Upwork Link'];
  const link =
    linkField?.url ||
    linkField?.rich_text?.[0]?.plain_text ||
    linkField?.title?.[0]?.plain_text ||
    null;

  // ── Upwork ID (de la propiedad o extraído del link) ──
  const upworkIdField = props['Upwork ID'] || props['UpworkID'] || props['upwork_id'];
  let upworkId =
    upworkIdField?.rich_text?.[0]?.plain_text ||
    upworkIdField?.number?.toString() ||
    upworkIdField?.title?.[0]?.plain_text ||
    null;

  if (!upworkId && link) {
    const m =
      link.match(/~0?(\d{10,})/) ||
      link.match(/jobs\/~0?(\d{10,})/) ||
      link.match(/(\d{10,})/);
    if (m) upworkId = m[1];
  }

  if (!upworkId) continue; // sin upwork_id no podemos upsertear

  // ── Ticket (parse "$X - $Y" o "$X") ──
  const ticketField = props['Ticket'];
  const ticketRaw =
    ticketField?.formula?.string ||
    ticketField?.rich_text?.[0]?.plain_text ||
    ticketField?.select?.name ||
    '';

  let ticket = null;
  const rangeMatch = ticketRaw.match(/\$?\s*([\d.]+)\s*[-–]\s*\$?\s*([\d.]+)/);
  if (rangeMatch) {
    ticket = parseFloat(rangeMatch[2]); // máximo del rango
  } else {
    const single = ticketRaw.match(/\$?\s*([\d.]+)/);
    if (single) ticket = parseFloat(single[1]);
  }

  // ── AI Summary ──
  const aiField = props['AI Summary'] || props['ai_summary'];
  const ai_summary =
    aiField?.rich_text?.map(t => t.plain_text).join('').trim() || null;

  // ── Country (si lo tenés en Notion) ──
  const countryField = props['Country'] || props['country'];
  const country =
    countryField?.select?.name ||
    countryField?.rich_text?.[0]?.plain_text ||
    null;

  out.push({
    json: {
      upwork_id: upworkId,
      title,
      description,
      link,
      ticket,
      ticket_currency: ticket != null ? 'USD' : null,
      country,
      ai_summary,
      status: 'new',
      notion_page_id: page.id, // para referencia cruzada
    },
  });
}

return out;
